func filter(xs []int, keep func(int) bool) []int {
	out := make([]int, 0, len(xs))
	for _, x := range xs {
		if keep(x) {
			out = append(out, x)
		}
	}
	return out
}

func main() { fmt.Println(filter([]int{1, 2, 3}, func(i int) bool { return i > 1 })) }

