	"strings"
)

func render(rows [][]string) string {
	var b strings.Builder
	for _, row := range rows {
		for i, c := range row {
			if i > 0 {
				b.WriteByte(',')
			}
			b.WriteString(c)
		}
		b.WriteByte('\n')
	}
	return b.String()
}

func main() { fmt.Println(render([][]string{{"a", "b"}})) }

