package main

import (
	"errors"
	"fmt"
)

func validateAll(checks []func() error) error {
	var errs []error
	for _, c := range checks {
		if e := c(); e != nil {
			errs = append(errs, e)
		}
	}
	return errors.Join(errs...)
}

func main() { fmt.Println(validateAll(nil)) }
